import{_ as e,o as n,c as r,ag as d}from"./chunks/framework.5wcOFaQl.js";const g=JSON.parse('{"title":"Note-Taking, NPC-Building & Productivity 📝🤖💼","description":"","frontmatter":{},"headers":[],"relativePath":"skills/notes-npc-productivity.md","filePath":"skills/notes-npc-productivity.md"}'),a={name:"skills/notes-npc-productivity.md"};function i(o,t,s,l,c,h){return n(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="note-taking-npc-building-productivity-📝🤖💼" tabindex="-1">Note-Taking, NPC-Building &amp; Productivity 📝🤖💼 <a class="header-anchor" href="#note-taking-npc-building-productivity-📝🤖💼" aria-label="Permalink to &quot;Note-Taking, NPC-Building &amp; Productivity 📝🤖💼&quot;">​</a></h1><hr><h2 id="📝-note-taking" tabindex="-1">📝 Note-Taking <a class="header-anchor" href="#📝-note-taking" aria-label="Permalink to &quot;📝 Note-Taking&quot;">​</a></h2><div class="skill-card"><h3 id="📌-auf-einen-blick" tabindex="-1">📌 Auf einen Blick <a class="header-anchor" href="#📌-auf-einen-blick" aria-label="Permalink to &quot;📌 Auf einen Blick&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Skill</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>obsidian</strong></td><td>Notizen im Obsidian-Vault lesen, suchen, erstellen</td></tr></tbody></table></div><div class="skill-card"><h3 id="🗃️-obsidian" tabindex="-1">🗃️ obsidian <a class="header-anchor" href="#🗃️-obsidian" aria-label="Permalink to &quot;🗃️ obsidian&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>🎯 Auslöser</strong></td><td><code>„Such in meinen Notizen&quot;</code> · <code>„Erstell ne Notiz&quot;</code> · <code>„Obsidian&quot;</code></td></tr><tr><td><strong>⚡ Features</strong></td><td>Lese-, Such- und Schreibzugriff auf deinen Obsidian-Vault — direkt aus der Session. Ideal für Wissensmanagement, Recherche-Dokumentation und Daily Notes.</td></tr><tr><td><strong>⚠️ Fallstricke</strong></td><td>Keine Vault-Strukturänderungen (Ordner anlegen/verschieben). Kein Graph-View oder Tag-Explorer.</td></tr></tbody></table></div><hr><h2 id="🤖-opensim-npc-building" tabindex="-1">🤖 OpenSim NPC Building <a class="header-anchor" href="#🤖-opensim-npc-building" aria-label="Permalink to &quot;🤖 OpenSim NPC Building&quot;">​</a></h2><p>KI-gestützte NPCs für OpenSimulator-Welten.</p><div class="skill-card"><h3 id="📌-auf-einen-blick-1" tabindex="-1">📌 Auf einen Blick <a class="header-anchor" href="#📌-auf-einen-blick-1" aria-label="Permalink to &quot;📌 Auf einen Blick&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Skill</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>opensim-npc-building</strong></td><td>Bau-Workflows für den OpenSim NPC Bot (Ollama Bot)</td></tr><tr><td><strong>opensim-ossl-npc-bridge</strong></td><td>OSSL NPC + Hermes Agent Bridge — Realtime AI NPC</td></tr></tbody></table></div><div class="skill-card"><h3 id="🏗️-opensim-npc-building" tabindex="-1">🏗️ opensim-npc-building <a class="header-anchor" href="#🏗️-opensim-npc-building" aria-label="Permalink to &quot;🏗️ opensim-npc-building&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>🎯 Auslöser</strong></td><td><code>„NPC bauen für OpenSim&quot;</code> · <code>„Ollama Bot&quot;</code></td></tr><tr><td><strong>⚡ Features</strong></td><td>Bau-Workflows für den OpenSim NPC Bot. Nutzt Ollama für lokale KI und GridClient zur Steuerung in OpenSim.</td></tr><tr><td><strong>⚠️ Fallstricke</strong></td><td>Erfordert laufenden Ollama-Dienst. GridClient muss kompatibel zur OpenSim-Version sein.</td></tr></tbody></table></div><div class="skill-card"><h3 id="🔗-opensim-ossl-npc-bridge" tabindex="-1">🔗 opensim-ossl-npc-bridge <a class="header-anchor" href="#🔗-opensim-ossl-npc-bridge" aria-label="Permalink to &quot;🔗 opensim-ossl-npc-bridge&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>🎯 Auslöser</strong></td><td><code>„Echtzeit-NPC in OpenSim&quot;</code> · <code>„OSSL + Hermes&quot;</code></td></tr><tr><td><strong>⚡ Features</strong></td><td>Brücke zwischen OpenSims OSSL-Skriptsprache und Hermes Agent. NPCs kommunizieren in Echtzeit mit Hermes&#39; KI — für dynamische Dialoge und reaktives Verhalten.</td></tr><tr><td><strong>⚠️ Fallstricke</strong></td><td>Latenz bei langsamer Netzwerkanbindung. OSSL-Rechte im OpenSim müssen freigegeben sein.</td></tr></tbody></table></div><hr><h2 id="💼-productivity" tabindex="-1">💼 Productivity <a class="header-anchor" href="#💼-productivity" aria-label="Permalink to &quot;💼 Productivity&quot;">​</a></h2><p>Dokumente, Präsentationen, Termine, E-Mails und mehr.</p><div class="skill-card"><h3 id="📌-auf-einen-blick-2" tabindex="-1">📌 Auf einen Blick <a class="header-anchor" href="#📌-auf-einen-blick-2" aria-label="Permalink to &quot;📌 Auf einen Blick&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Skill</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>airtable</strong></td><td>Airtable REST API via curl. CRUD, Filter, Upserts</td></tr><tr><td><strong>google-workspace</strong></td><td>Gmail, Kalender, Drive, Docs, Sheets via gws CLI oder Python</td></tr><tr><td><strong>linear</strong></td><td>Linear: Issues, Projekte, Teams via GraphQL + curl</td></tr><tr><td><strong>maps</strong></td><td>Geocoding, POIs, Routen, Zeitzonen via OpenStreetMap/OSRM</td></tr><tr><td><strong>nano-pdf</strong></td><td>PDF-Text/Tippfehler/Titel editieren via nano-pdf CLI</td></tr><tr><td><strong>notion</strong></td><td>Notion API via curl: Pages, Databases, Blocks, Search</td></tr><tr><td><strong>ocr-and-documents</strong></td><td>Text aus PDFs/Scans extrahieren (pymupdf, marker-pdf)</td></tr><tr><td><strong>powerpoint</strong></td><td>.pptx-Präsentationen erstellen, lesen, bearbeiten</td></tr></tbody></table></div><div class="skill-card"><h3 id="🧩-google-workspace" tabindex="-1">🧩 google-workspace <a class="header-anchor" href="#🧩-google-workspace" aria-label="Permalink to &quot;🧩 google-workspace&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>🎯 Auslöser</strong></td><td><code>„Schreib ne Mail&quot;</code> · <code>„Termin im Kalender&quot;</code> · <code>„Google Doc lesen&quot;</code></td></tr><tr><td><strong>⚡ Features</strong></td><td>Vollständige Integration: Mails senden/lesen via Gmail, Termine verwalten im Kalender, Dokumente bearbeiten in Docs/Sheets.</td></tr><tr><td><strong>⚠️ Fallstricke</strong></td><td>OAuth-Refresh-Token nötig. Rate-Limits bei vielen API-Calls. Kein Zugriff auf Google Chat/Meet.</td></tr></tbody></table></div><div class="skill-card"><h3 id="🧩-notion" tabindex="-1">🧩 notion <a class="header-anchor" href="#🧩-notion" aria-label="Permalink to &quot;🧩 notion&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>🎯 Auslöser</strong></td><td><code>„Notion-Seite lesen&quot;</code> · <code>„Datenbank in Notion&quot;</code> · <code>„Eintrag erstellen&quot;</code></td></tr><tr><td><strong>⚡ Features</strong></td><td>Steuert Notion via REST API: Pages lesen/schreiben, Datenbanken abfragen, Blöcke manipulieren, suchen.</td></tr><tr><td><strong>⚠️ Fallstricke</strong></td><td>Notion-API-Token erforderlich. Kein Zugriff auf geschützte Seiten ohne Integration-Einladung.</td></tr></tbody></table></div><div class="skill-card"><h3 id="🧩-ocr-and-documents" tabindex="-1">🧩 ocr-and-documents <a class="header-anchor" href="#🧩-ocr-and-documents" aria-label="Permalink to &quot;🧩 ocr-and-documents&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>🎯 Auslöser</strong></td><td><code>„Scan einscannen&quot;</code> · <code>„PDF als Text&quot;</code> · <code>„Dokument auslesen&quot;</code></td></tr><tr><td><strong>⚡ Features</strong></td><td>Extrahiert Text aus PDFs und Bildern via pymupdf und marker-pdf. Erkennt Tabellen, Layouts und Strukturen.</td></tr><tr><td><strong>⚠️ Fallstricke</strong></td><td>Handschrift wird nicht erkannt. Sehr große PDFs (&gt;100 Seiten) können timeouten.</td></tr></tbody></table></div><div class="skill-card"><h3 id="🧩-nano-pdf" tabindex="-1">🧩 nano-pdf <a class="header-anchor" href="#🧩-nano-pdf" aria-label="Permalink to &quot;🧩 nano-pdf&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>🎯 Auslöser</strong></td><td><code>„PDF-Tippfehler korrigieren&quot;</code> · <code>„PDF-Titel ändern&quot;</code></td></tr><tr><td><strong>⚡ Features</strong></td><td>Gezielte Text-Änderungen in PDFs — Tippfehler korrigieren, Titel ändern, Texte ersetzen — ohne Neu-Generierung.</td></tr><tr><td><strong>⚠️ Fallstricke</strong></td><td>Nur für digitale (nicht gescannte) PDFs. Layout kann bei Ersetzung längerer Texte brechen.</td></tr></tbody></table></div>',19)])])}const b=e(a,[["render",i]]);export{g as __pageData,b as default};
